sys_script_include.script:
var IDPSecurity = Class.create();
IDPSecurity.prototype = {
    initialize: function() {
    },

    hasCapability: function(capabilityId) {
        var userCapabilities = this.getUserCapabilityIds();
        return userCapabilities.indexOf(capabilityId) !== -1;
    },

    hasCapabilityForUser: function(userId, capabilityId) {
        var gr = new GlideRecord('sys_user_has_role');
        gr.addQuery('user', userId);
        gr.addQuery('role.name', 'LIKE', 'x_146833_idpkiroq.');
        gr.query();

        var roleIds = [];
        while (gr.next()) {
            roleIds.push(gr.role.toString());
        }

        if (roleIds.length === 0) {
            return false;
        }

        var capGr = new GlideRecord('u_role_capability_map');
        capGr.addQuery('role', 'IN', roleIds.join(','));
        capGr.addQuery('capability', capabilityId);
        capGr.query();

        return capGr.hasNext();
    },

    getUserCapabilityIds: function() {
        var user = gs.getUser();
        var capabilityIds = [];

        var gr = new GlideRecord('sys_user_has_role');
        gr.addQuery('user', user.getID());
        gr.addQuery('role.name', 'LIKE', 'x_146833_idpkiroq.');
        gr.query();

        var roleIds = [];
        while (gr.next()) {
            roleIds.push(gr.role.toString());
        }

        if (roleIds.length === 0) {
            return capabilityIds;
        }

        var capGr = new GlideRecord('u_role_capability_map');
        capGr.addQuery('role', 'IN', roleIds.join(','));
        capGr.query();

        while (capGr.next()) {
            capabilityIds.push(capGr.capability.toString());
        }

        return capabilityIds;
    },

    type: 'IDPSecurity'
};
